"function liveText(key){const ru={runtime_title:'\\u0416\\u0438\\u0432\\u0430\\u044F \\u043F\\u0440\\u043E\\u0432\\u0435\\u0440\\u043A\\u0430',test_output:'\\u041F\\u0440\\u043E\\u0432\\u0435\\u0440\\u0438\\u0442\\u044C \\u0432\\u044B\\u0445\\u043E\\u0434',testing:'\\u0418\\u0434\\u0451\\u0442 \\u0442\\u0435\\u0441\\u0442',apply_before_test:'\\u041F\\u0435\\u0440\\u0435\\u0434 \\u0442\\u0435\\u0441\\u0442\\u043E\\u043C \\u0447\\u0435\\u0440\\u043D\\u043E\\u0432\\u0438\\u043A \\u0441\\u043E\\u0445\\u0440\\u0430\\u043D\\u044F\\u0435\\u0442\\u0441\\u044F \\u0438 \\u0441\\u0440\\u0430\\u0437\\u0443 \\u043F\\u0440\\u0438\\u043C\\u0435\\u043D\\u044F\\u0435\\u0442\\u0441\\u044F \\u043D\\u0430 \\u043F\\u043B\\u0430\\u0442\\u0435.',missing_output_id:'\\u0414\\u043B\\u044F \\u0442\\u0435\\u0441\\u0442\\u0430 \\u043D\\u0443\\u0436\\u043D\\u043E \\u0437\\u0430\\u0434\\u0430\\u0442\\u044C ID \\u0432\\u044B\\u0445\\u043E\\u0434\\u0430.',output_on:'\\u0412\\u044B\\u0445\\u043E\\u0434 \\u0432\\u043A\\u043B\\u044E\\u0447\\u0435\\u043D',output_off:'\\u0412\\u044B\\u0445\\u043E\\u0434 \\u0432\\u044B\\u043A\\u043B\\u044E\\u0447\\u0435\\u043D',level:'\\u0423\\u0440\\u043E\\u0432\\u0435\\u043D\\u044C',target:'\\u0426\\u0435\\u043B\\u044C',moving:'\\u0414\\u0432\\u0438\\u0436\\u0435\\u043D\\u0438\\u0435',idle:'\\u041E\\u0436\\u0438\\u0434\\u0430\\u043D\\u0438\\u0435',input_on:'\\u0412\\u0445\\u043E\\u0434 \\u0430\\u043A\\u0442\\u0438\\u0432\\u0435\\u043D',input_off:'\\u0412\\u0445\\u043E\\u0434 \\u043D\\u0435\\u0430\\u043A\\u0442\\u0438\\u0432\\u0435\\u043D',button_pressed:'\\u041A\\u043D\\u043E\\u043F\\u043A\\u0430 \\u043D\\u0430\\u0436\\u0430\\u0442\\u0430',button_released:'\\u041A\\u043D\\u043E\\u043F\\u043A\\u0430 \\u043E\\u0442\\u043F\\u0443\\u0449\\u0435\\u043D\\u0430',live_unavailable:'\\u0416\\u0438\\u0432\\u044B\\u0435 \\u0434\\u0430\\u043D\\u043D\\u044B\\u0435 \\u0435\\u0449\\u0451 \\u043D\\u0435 \\u043F\\u043E\\u043B\\u0443\\u0447\\u0435\\u043D\\u044B.',test_started:'\\u0422\\u0435\\u0441\\u0442 \\u0432\\u044B\\u0445\\u043E\\u0434\\u0430 \\u0437\\u0430\\u043F\\u0443\\u0449\\u0435\\u043D'};const en={runtime_title:'Live check',test_output:'Test output',testing:'Testing',apply_before_test:'Before testing, the draft config is saved and applied to the board.',missing_output_id:'Output ID is required for test.',output_on:'Output ON',output_off:'Output OFF',level:'Level',target:'Target',moving:'Moving',idle:'Idle',input_on:'Input active',input_off:'Input inactive',button_pressed:'Button pressed',button_released:'Button released',live_unavailable:'Live data is not available yet.',test_started:'Output test started'};const dict=lang==='ru'?ru:en;return dict[key]||key;}"
"function mapLabel(map,key){const v=map[key]||{};return v[lang]||v.en||v.ru||key;}"
"function normalizeBoardProfile(v){return BOARD_PROFILES.includes(v)?v:'esp32-c3-supermini';}"
"function boardProfileName(profile){return mapLabel(BOARD_PROFILE_LABELS,normalizeBoardProfile(profile));}"
"function allowedGpios(profile){const key=normalizeBoardProfile(profile);const gpios=ALLOWED_GPIOS_BY_PROFILE[key]||ALLOWED_GPIOS_BY_PROFILE['esp32-c3-supermini'];return gpios.slice();}"
"function gpioAllowed(profile,gpio){return allowedGpios(profile).includes(Number(gpio));}"
"function gpioForbiddenText(profile,gpio){return lang==='ru'?`GPIO${gpio} \\u043D\\u0435\\u0434\\u043E\\u043F\\u0443\\u0441\\u0442\\u0438\\u043C \\u0434\\u043B\\u044F \\u043F\\u0440\\u043E\\u0444\\u0438\\u043B\\u044F ${boardProfileName(profile)}`:`GPIO${gpio} is not allowed for profile ${boardProfileName(profile)}`;}"
"function invalidCurrentGpioLabel(profile,gpio){return lang==='ru'?`GPIO${gpio} (\\u0442\\u0435\\u043A\\u0443\\u0449\\u0438\\u0439, \\u043D\\u0435\\u0434\\u043E\\u043F\\u0443\\u0441\\u0442\\u0438\\u043C \\u0434\\u043B\\u044F ${boardProfileName(profile)})`:`GPIO${gpio} (current, not allowed for ${boardProfileName(profile)})`;}"
"function gpioSaveBlockedText(){return lang==='ru'?'\\u0418\\u0441\\u043F\\u0440\\u0430\\u0432\\u044C\\u0442\\u0435 \\u043E\\u0448\\u0438\\u0431\\u043A\\u0438 GPIO \\u043F\\u0435\\u0440\\u0435\\u0434 \\u0441\\u043E\\u0445\\u0440\\u0430\\u043D\\u0435\\u043D\\u0438\\u0435\\u043C':'Fix GPIO errors before saving';}"
"function pinoutText(key){const ru={title:'\\u0421\\u0445\\u0435\\u043C\\u0430 \\u043F\\u0438\\u043D\\u043E\\u0432',click:'',schematic:'',free:'\\u0421\\u0432\\u043E\\u0431\\u043E\\u0434\\u0435\\u043D',output:'\\u0412\\u044B\\u0445\\u043E\\u0434',io:'\\u0412\\u0445\\u043E\\u0434/\\u043A\\u043D\\u043E\\u043F\\u043A\\u0430',sensor:'\\u0414\\u0430\\u0442\\u0447\\u0438\\u043A',reserved:'\\u0421\\u043B\\u0443\\u0436\\u0435\\u0431\\u043D\\u044B\\u0439',special:'\\u0421\\u043F\\u0435\\u0446\\u043A\\u043E\\u043D\\u0442\\u0430\\u043A\\u0442',blocked:'\\u041D\\u0435\\u0434\\u043E\\u0441\\u0442\\u0443\\u043F\\u0435\\u043D',conflict:'\\u041A\\u043E\\u043D\\u0444\\u043B\\u0438\\u043A\\u0442',power:'\\u041F\\u0438\\u0442\\u0430\\u043D\\u0438\\u0435',ground:'\\u0417\\u0435\\u043C\\u043B\\u044F',used_by:'\\u0418\\u0441\\u043F\\u043E\\u043B\\u044C\\u0437\\u0443\\u0435\\u0442\\u0441\\u044F',profile:'\\u041F\\u0440\\u043E\\u0444\\u0438\\u043B\\u044C',reason:'\\u041F\\u0440\\u0438\\u0447\\u0438\\u043D\\u0430'};const en={title:'Pinout map',click:'',schematic:'',free:'Free',output:'Output',io:'Input/button',sensor:'Sensor',reserved:'Reserved',special:'Special',blocked:'Blocked',conflict:'Conflict',power:'Power',ground:'Ground',used_by:'Used by',profile:'Profile',reason:'Reason'};const dict=lang==='ru'?ru:en;return dict[key]||key;}"
"function servicePinReason(gpio){const reason=SERVICE_PIN_REASONS[gpio];if(!reason)return'';return reason[lang]||reason.en||'';}"
"function summarizePinUsage(profile,gpio,usage){const entries=usage[String(gpio)]||[];const shareOk=entries.length>1&&entries.every(e=>e.share&&e.share===entries[0].share);if(entries.length>1&&!shareOk){return{state:'conflict',title:pinoutText('conflict'),lines:entries.map(e=>e.label)};}if(entries.length){const state=entries.some(e=>e.kind==='output')?'output':entries.some(e=>e.kind==='sensor')?'sensor':'io';return{state,title:pinoutText(state),lines:entries.map(e=>e.label)};}if(SERVICE_PIN_REASONS[gpio]&&!gpioAllowed(profile,gpio)){return{state:'reserved',title:pinoutText('reserved'),lines:[servicePinReason(gpio)]};}if(!gpioAllowed(profile,gpio)){return{state:'blocked',title:pinoutText('blocked'),lines:[gpioForbiddenText(profile,gpio)]};}return{state:'free',title:pinoutText('free'),lines:[]};}"
"function pinoutLegendHtml(){const items=[['power',pinoutText('power')],['ground',pinoutText('ground')],['free',pinoutText('free')],['output',pinoutText('output')],['io',pinoutText('io')],['sensor',pinoutText('sensor')],['special',pinoutText('special')],['reserved',pinoutText('reserved')],['blocked',pinoutText('blocked')],['conflict',pinoutText('conflict')]];return items.map(([state,label])=>`<span class='pin-chip'><i class='pin-${state}'></i>${esc(label)}</span>`).join('');}"
"function setMsg(msg,ok){const el=document.getElementById('msg');el.textContent=msg||'';el.className=ok?'ok':'err';}"
"function ensure(){cfg.outputs=Array.isArray(cfg.outputs)?cfg.outputs:[];cfg.inputs=Array.isArray(cfg.inputs)?cfg.inputs:[];cfg.buttons=Array.isArray(cfg.buttons)?cfg.buttons:[];cfg.sensors=Array.isArray(cfg.sensors)?cfg.sensors:[];cfg.device=cfg.device||{};cfg.connectivity=cfg.connectivity||{};cfg.connectivity.ap=cfg.connectivity.ap||{};cfg.connectivity.sta=cfg.connectivity.sta||{};cfg.connectivity.mqtt=cfg.connectivity.mqtt||{};}"
"function gpioOptions(selected,profile){const boardProfile=normalizeBoardProfile(profile);const options=allowedGpios(boardProfile);const numeric=Number(selected);if(selected!==undefined&&selected!==null&&selected!==''&&!Number.isNaN(numeric)&&!options.includes(numeric))options.push(numeric);options.sort((a,b)=>a-b);return options.map(g=>{const invalid=!gpioAllowed(boardProfile,g);const label=invalid?invalidCurrentGpioLabel(boardProfile,g):`GPIO${g}`;return `<option value='${g}' ${Number(selected)===g?'selected':''}>${esc(label)}</option>`;}).join('');}"
"function gpioOptionsOptional(selected,profile){const boardProfile=normalizeBoardProfile(profile);const options=allowedGpios(boardProfile);const numeric=Number(selected);if(selected!==undefined&&selected!==null&&selected!==''&&!Number.isNaN(numeric)&&!options.includes(numeric))options.push(numeric);options.sort((a,b)=>a-b);const selectedText=selected===undefined||selected===null||selected===''||Number.isNaN(numeric)?'selected':'';const emptyOption=`<option value='' ${selectedText}>${esc(uiText('not_used'))}</option>`;return emptyOption+options.map(g=>{const invalid=!gpioAllowed(boardProfile,g);const label=invalid?invalidCurrentGpioLabel(boardProfile,g):`GPIO${g}`;return `<option value='${g}' ${Number(selected)===g?'selected':''}>${esc(label)}</option>`;}).join('');}"
"function optionalGpioValue(value){const num=Number(value);return Number.isInteger(num)&&num>=0?num:'';}"
"function adcFeedbackGpios(profile){return allowedGpios(profile).filter(g=>[0,1,2,3,4].includes(Number(g)));}"
"function gpioOptionsAdc(selected,profile){const boardProfile=normalizeBoardProfile(profile);const options=adcFeedbackGpios(boardProfile);const numeric=Number(selected);if(selected!==undefined&&selected!==null&&selected!==''&&!Number.isNaN(numeric)&&!options.includes(numeric))options.push(numeric);options.sort((a,b)=>a-b);return options.map(g=>{const invalid=!adcFeedbackGpios(boardProfile).includes(Number(g));const label=invalid?invalidCurrentGpioLabel(boardProfile,g):`GPIO${g}`;return `<option value='${g}' ${Number(selected)===g?'selected':''}>${esc(label)}</option>`;}).join('');}"
"function setOutputType(idx,value){const o=cfg.outputs[idx]||{};const boardProfile=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));let fallback=pick(o.gpio,0);o.type=value;if(value==='servo_3wire'){if(o.default_level===undefined)o.default_level=0;if(o.min_us===undefined)o.min_us=500;if(o.max_us===undefined)o.max_us=2500;}else if(value==='servo_5wire'){if(o.default_level===undefined)o.default_level=0;if(o.gpio_b===undefined){const alt=allowedGpios(boardProfile).find(g=>Number(g)!==Number(pick(o.gpio,0)));o.gpio_b=(alt!==undefined?alt:fallback);}if(o.feedback_gpio===undefined){const adc=adcFeedbackGpios(boardProfile).find(g=>Number(g)!==Number(pick(o.gpio,0))&&Number(g)!==Number(pick(o.gpio_b,-1)));o.feedback_gpio=(adc!==undefined?adc:0);}if(o.feedback_min_raw===undefined)o.feedback_min_raw=300;if(o.feedback_max_raw===undefined)o.feedback_max_raw=3700;if(o.deadband_pct===undefined)o.deadband_pct=2;if(o.move_timeout_ms===undefined)o.move_timeout_ms=15000;if(o.reverse_direction===undefined)o.reverse_direction=false;}cfg.outputs[idx]=o;render();}"
"function ws2812ModeOptions(selected){return [['rgb',uiText('ws_mode_rgb')],['mono_triplet',uiText('ws_mode_mono')]].map(([v,label])=>`<option value='${v}' ${String(selected)===v?'selected':''}>${esc(label)}</option>`).join('');}"
"function ws2812TransitionOptions(selected,mode){const items=(mode==='mono_triplet')?[['none',uiText('ws_transition_none')],['fade',uiText('ws_transition_fade')],['wipe',uiText('ws_transition_wipe')]]:[['none',uiText('ws_transition_none')],['fade',uiText('ws_transition_fade')]];return items.map(([v,label])=>`<option value='${v}' ${String(selected)===v?'selected':''}>${esc(label)}</option>`).join('');}"
"function ws2812ColorOrderOptions(selected){return ['RGB','RBG','GRB','GBR','BRG','BGR'].map(v=>`<option value='${v}' ${String(selected)===v?'selected':''}>${v}</option>`).join('');}"
"function normalizeWs2812Transition(value,mode){if(mode==='mono_triplet')return(value==='fade'||value==='wipe')?value:'none';return value==='fade'?'fade':'none';}"
"function setWs2812Mode(idx,value){cfg.outputs[idx].mode=value;if(value!=='mono_triplet'&&cfg.outputs[idx].transition_style==='wipe')cfg.outputs[idx].transition_style='fade';render();}"
"function pwmPowerRelayEnabled(output){const gpio=Number(output&&output.power_relay_gpio);return Number.isInteger(gpio)&&gpio>=0;}"
"function togglePwmPowerRelay(idx,enabled){if(enabled){cfg.outputs[idx].power_relay_gpio=0;if(cfg.outputs[idx].power_relay_active_level===undefined)cfg.outputs[idx].power_relay_active_level=1;}else{delete cfg.outputs[idx].power_relay_gpio;}render();}"
"function setOptionalPwmPowerRelayGpio(idx,value){if(value===''){delete cfg.outputs[idx].power_relay_gpio;}else{cfg.outputs[idx].power_relay_gpio=Number(value);}render();}"
"function enumOptions(values,selected,map){return values.map(v=>`<option value='${esc(v)}' ${String(selected)===String(v)?'selected':''}>${esc(mapLabel(map||{},v))}</option>`).join('');}"
"function boardOptions(selected){return BOARD_PROFILES.map(v=>`<option value='${esc(v)}' ${String(selected)===String(v)?'selected':''}>${esc(mapLabel(BOARD_PROFILE_LABELS,v))}</option>`).join('');}"
"function setField(section,idx,key,value){cfg[section][idx][key]=value;render();}"
"function setNested(section,idx,parent,key,value){cfg[section][idx][parent]=cfg[section][idx][parent]||{};cfg[section][idx][parent][key]=value;render();}"
"function removeItem(section,idx){cfg[section].splice(idx,1);render();}"
"function ioEntries(){const list=[];cfg.inputs.forEach((o,i)=>list.push({section:'inputs',idx:i,kind:'input',data:o}));cfg.buttons.forEach((o,i)=>list.push({section:'buttons',idx:i,kind:'button',data:o}));return list;}"
"function inputFromButton(src){return{id:src.id||'',name:src.name||'',type:'digital',enabled:src.enabled!==false,gpio:pick(src.gpio,0),pull:pick(src.pull,'up'),inverted:!!src.inverted,role:'generic_binary'};}"
"function buttonFromInput(src){return{id:src.id||'',name:src.name||'',enabled:src.enabled!==false,gpio:pick(src.gpio,0),pull:pick(src.pull,'up'),inverted:!!src.inverted,long_press_ms:1000,actions:{short:{type:'master_toggle'},long:{type:'none'}}};}"
"function changeIoKind(section,idx,nextKind){if(section==='inputs'&&nextKind==='input')return;if(section==='buttons'&&nextKind==='button')return;const src=cfg[section][idx];cfg[section].splice(idx,1);if(nextKind==='button'){cfg.buttons.push(buttonFromInput(src));}else{cfg.inputs.push(inputFromButton(src));}render();}"
"function actionEditor(section,idx,which,a){const cur=a||{};return `<div class='row3'><div><label>${t(which+'_action')}</label><select onchange=\\\"setNested('${section}',${idx},'actions','${which}',Object.assign((((cfg['${section}'][${idx}].actions||{})['${which}'])||{}),{type:this.value}))\\\">${enumOptions(BUTTON_ACTIONS,pick(cur.type,'none'),BUTTON_ACTION_LABELS)}</select></div><div><label>${t(which+'_target')}</label><input value='${esc(pick(cur.target,''))}' oninput=\\\"setNested('${section}',${idx},'actions','${which}',Object.assign((((cfg['${section}'][${idx}].actions||{})['${which}'])||{}),{target:this.value}))\\\"/></div><div><label>${t(which+'_value')}</label><input value='${esc(cur.step!==undefined?cur.step:(cur.value!==undefined?cur.value:''))}' oninput=\\\"const obj=Object.assign((((cfg['${section}'][${idx}].actions||{})['${which}'])||{}),{});if(obj.type==='set_output'){obj.value=(this.value==='true'||this.value==='1'||this.value==='on');}else{obj.step=Number(this.value||10);}setNested('${section}',${idx},'actions','${which}',obj)\\\"/></div></div>`;}"

"function findLiveById(items,id){return(items||[]).find(item=>String((item&&item.id)||'')===String(id||''))||null;}"
"function ensureLiveShells(){}"
"function outputStatusForDraft(output){const type=pick(output&&output.type,'relay');if(type==='relay'){const on=!!pick(output&&output.default_on,false);return{state:on?'on':'off',text:on?liveText('output_on'):liveText('output_off')}}if(type==='servo_5wire'){return{state:'neutral',text:`${liveText('target')}: ${Number(pick(output&&output.default_level,0))}%`}}if(type==='pwm'||type==='ws2812'||type==='servo_3wire'){return{state:'neutral',text:`${liveText('level')}: ${Number(pick(output&&output.default_level,0))}%`}}return{state:'neutral',text:liveText('live_unavailable')}}"
"function renderOutputLiveCard(index,output){const live=findLiveById(liveModules.outputs,output&&output.id);const fallback=outputStatusForDraft(output);const badges=[];if(live){badges.push(`<span class='badge badge-${live.power?'on':'off'}'>${esc(live.power?liveText('output_on'):liveText('output_off'))}</span>`);if(typeof live.level==='number')badges.push(`<span class='badge badge-neutral'>${esc(`${liveText('level')}: ${Math.round(live.level)}%`)}</span>`);if(typeof live.target_level==='number')badges.push(`<span class='badge badge-${live.moving?'moving':'neutral'}'>${esc(`${liveText('target')}: ${Math.round(live.target_level)}%`)}</span>`);if(live.moving)badges.push(`<span class='badge badge-moving'>${esc(liveText('moving'))}</span>`);if(live.test_active)badges.push(`<span class='badge badge-testing'>${esc(liveText('testing'))}</span>`);}else{badges.push(`<span class='badge badge-${fallback.state}'>${esc(fallback.text)}</span>`);}const disabled=String((output&&output.id)||'').trim()?'':'disabled';const hint=live?liveText('apply_before_test'):liveText('live_unavailable');return `<div id='output_live_${index}'><div class='livebox'><div class='livehead'><div><div class='livetitle'>${esc(liveText('runtime_title'))}</div><div class='livehint'>${esc(hint)}</div></div><button class='smallbtn' onclick='testOutput(${index})' ${disabled}>${esc(liveText('test_output'))}</button></div><div class='livebadges'>${badges.join('')}</div></div></div>`;}"
"function renderIoLiveCard(entry){const live=entry.kind==='button'?findLiveById(liveModules.buttons,entry.data.id):findLiveById(liveModules.inputs,entry.data.id);let state='neutral';let label=liveText('live_unavailable');if(live){const active=entry.kind==='button'?!!live.pressed:!!live.state;state=active?'active':'released';label=active?(entry.kind==='button'?liveText('button_pressed'):liveText('input_on')):(entry.kind==='button'?liveText('button_released'):liveText('input_off'));}const hint=live?`GPIO ${pick(live.gpio,entry.data.gpio)}`:liveText('live_unavailable');return `<div id='io_live_${entry.section}_${entry.idx}'><div class='livebox'><div class='livehead'><div><div class='livetitle'>${esc(liveText('runtime_title'))}</div><div class='livehint'>${esc(hint)}</div></div></div><div class='livebadges'><span class='badge badge-${state}'>${esc(label)}</span></div></div></div>`;}"
"function refreshLiveWidgets(){if(!cfg)return;cfg.outputs.forEach((output,index)=>{const el=document.getElementById(`output_live_${index}`);if(el)el.outerHTML=renderOutputLiveCard(index,output);});ioEntries().forEach(entry=>{const el=document.getElementById(`io_live_${entry.section}_${entry.idx}`);if(el)el.outerHTML=renderIoLiveCard(entry);});}"
"function pollLiveModules(silent){if(livePollInFlight)return livePollInFlight;livePollInFlight=fetch('/api/modules').then(r=>{if(!r.ok)throw new Error(`HTTP ${r.status}`);return r.json();}).then(j=>{liveModules={outputs:Array.isArray(j.outputs)?j.outputs:[],inputs:Array.isArray(j.inputs)?j.inputs:[],buttons:Array.isArray(j.buttons)?j.buttons:[],sensors:Array.isArray(j.sensors)?j.sensors:[]};refreshLiveWidgets();}).catch(e=>{if(!silent)setMsg(String(e),false);}).finally(()=>{livePollInFlight=null;});return livePollInFlight;}"
"function startLivePolling(){if(livePollTimer)return;livePollTimer=window.setInterval(()=>{pollLiveModules(true);},1000);}"
"async function testOutput(index){try{const output=cfg.outputs[index];if(!output)throw new Error('Output not found');if(!String(output.id||'').trim())throw new Error(liveText('missing_output_id'));await saveOnly();const applyResp=await fetch('/api/apply',{method:'POST'});if(!applyResp.ok)throw new Error(await applyResp.text()||(`HTTP ${applyResp.status}`));const resp=await fetch(`/api/modules/${encodeURIComponent(String(output.id).trim())}/action`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({test:true,duration_ms:1200})});const text=await resp.text();if(!resp.ok)throw new Error(text||(`HTTP ${resp.status}`));setMsg(liveText('test_started'),true);await pollLiveModules(true);window.setTimeout(()=>{pollLiveModules(true);},1400);}catch(e){setMsg(String(e),false);}}"
"function renderOutputs(){const boardProfile=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));document.getElementById('outputs').innerHTML=cfg.outputs.map((o,i)=>{const type=pick(o.type,'relay');const relayEnabled=pwmPowerRelayEnabled(o);const wsMode=pick(o.mode,'rgb');const wsTransition=normalizeWs2812Transition(pick(o.transition_style,'none'),wsMode);return `<div class='item'><div class='itemhead'><strong>${esc(o.name||o.id||(`${t('output_name')} ${i+1}`))}</strong><button class='danger' onclick='removeItem(\\\"outputs\\\",${i})'>${t('remove')}</button></div><div class='row'><div><label>${t('id')}</label><input value='${esc(o.id||'')}' oninput='setField(\\\"outputs\\\",${i},\\\"id\\\",this.value)'/></div><div><label>${t('name')}</label><input value='${esc(o.name||'')}' oninput='setField(\\\"outputs\\\",${i},\\\"name\\\",this.value)'/></div></div><div class='row3'><div><label>${t('type')}</label><select onchange='setOutputType(${i},this.value)'>${enumOptions(OUTPUT_TYPES,type,OUTPUT_TYPE_LABELS)}</select></div><div><label>${t('gpio')}</label><select onchange='setField(\\\"outputs\\\",${i},\\\"gpio\\\",Number(this.value))'>${gpioOptions(pick(o.gpio,0),boardProfile)}</select></div><div><label><input type='checkbox' ${o.enabled!==false?'checked':''} onchange='setField(\\\"outputs\\\",${i},\\\"enabled\\\",this.checked)' style='width:auto'/> ${t('enabled')}</label></div></div>${type==='relay'?`<div class='row'><div><label>${t('active_level')}</label><select onchange='setField(\\\"outputs\\\",${i},\\\"active_level\\\",Number(this.value))'><option value='1' ${Number(pick(o.active_level,1))===1?'selected':''}>1</option><option value='0' ${Number(pick(o.active_level,1))===0?'selected':''}>0</option></select></div><div><label><input type='checkbox' ${o.default_on?'checked':''} onchange='setField(\\\"outputs\\\",${i},\\\"default_on\\\",this.checked)' style='width:auto'/> ${t('default_on')}</label></div></div>`:''}${type==='pwm'?`<div class='row3'><div><label>${t('freq_hz')}</label><input type='number' value='${esc(pick(o.freq_hz,1000))}' oninput='setField(\\\"outputs\\\",${i},\\\"freq_hz\\\",Number(this.value||0))'/></div><div><label>${t('default_level')}</label><input type='number' min='0' max='100' value='${esc(pick(o.default_level,0))}' oninput='setField(\\\"outputs\\\",${i},\\\"default_level\\\",Number(this.value||0))'/></div><div><label>${uiText('pwm_max_level')}</label><input type='number' min='1' max='100' value='${esc(pick(o.max_level_pct,100))}' oninput='setField(\\\"outputs\\\",${i},\\\"max_level_pct\\\",Number(this.value||100))'/></div></div><div class='row'><div><label><input type='checkbox' ${relayEnabled?'checked':''} onchange='togglePwmPowerRelay(${i},this.checked)' style='width:auto'/> ${uiText('power_relay_enable')}</label></div><div><label><input type='checkbox' ${o.inverted?'checked':''} onchange='setField(\\\"outputs\\\",${i},\\\"inverted\\\",this.checked)' style='width:auto'/> ${t('inverted')}</label></div></div>${relayEnabled?`<div class='row3'><div><label>${uiText('power_relay_gpio')}</label><select onchange='setOptionalPwmPowerRelayGpio(${i},this.value)'>${gpioOptionsOptional(optionalGpioValue(o.power_relay_gpio),boardProfile)}</select></div><div><label>${uiText('power_relay_active_level')}</label><select onchange='setField(\\\"outputs\\\",${i},\\\"power_relay_active_level\\\",Number(this.value))'><option value='1' ${Number(pick(o.power_relay_active_level,1))===1?'selected':''}>1</option><option value='0' ${Number(pick(o.power_relay_active_level,1))===0?'selected':''}>0</option></select></div></div>`:''}`:''}${type==='ws2812'?`<div class='row3'><div><label>${uiText('ws_mode')}</label><select onchange='setWs2812Mode(${i},this.value)'>${ws2812ModeOptions(wsMode)}</select></div><div><label>${t('pixels')}</label><input type='number' value='${esc(pick(o.pixel_count,1))}' oninput='setField(\\\"outputs\\\",${i},\\\"pixel_count\\\",Number(this.value||1))'/></div><div><label>${t('color_order')}</label><select onchange='setField(\\\"outputs\\\",${i},\\\"color_order\\\",this.value)'>${ws2812ColorOrderOptions(pick(o.color_order,'GRB'))}</select></div></div><div class='row3'><div><label>${uiText('ws_transition')}</label><select onchange='setField(\\\"outputs\\\",${i},\\\"transition_style\\\",this.value)'>${ws2812TransitionOptions(wsTransition,wsMode)}</select></div><div><label>${uiText('ws_transition_ms')}</label><input type='number' min='0' max='5000' value='${esc(pick(o.transition_ms,300))}' oninput='setField(\\\"outputs\\\",${i},\\\"transition_ms\\\",Number(this.value||0))'/></div><div><label><input type='checkbox' ${o.default_power_on?'checked':''} onchange='setField(\\\"outputs\\\",${i},\\\"default_power_on\\\",this.checked)' style='width:auto'/> ${t('default_on')}</label></div></div>${wsMode==='mono_triplet'?`<div class='hint muted'>${uiText('ws_mono_order_hint')}</div>`:''}`:''}${type==='servo_3wire'?`<div class='row3'><div><label>${uiText('servo_default_position')}</label><input type='number' min='0' max='100' value='${esc(pick(o.default_level,0))}' oninput='setField(\\\"outputs\\\",${i},\\\"default_level\\\",Number(this.value||0))'/></div><div><label>${uiText('servo_min_us')}</label><input type='number' min='400' max='2600' value='${esc(pick(o.min_us,500))}' oninput='setField(\\\"outputs\\\",${i},\\\"min_us\\\",Number(this.value||500))'/></div><div><label>${uiText('servo_max_us')}</label><input type='number' min='400' max='2600' value='${esc(pick(o.max_us,2500))}' oninput='setField(\\\"outputs\\\",${i},\\\"max_us\\\",Number(this.value||2500))'/></div></div>`:''}${type==='servo_5wire'?`<div class='row3'><div><label>${uiText('servo_gpio_b')}</label><select onchange='setField(\\\"outputs\\\",${i},\\\"gpio_b\\\",Number(this.value))'>${gpioOptions(pick(o.gpio_b,1),boardProfile)}</select></div><div><label>${uiText('servo_feedback_gpio')}</label><select onchange='setField(\\\"outputs\\\",${i},\\\"feedback_gpio\\\",Number(this.value))'>${gpioOptionsAdc(pick(o.feedback_gpio,0),boardProfile)}</select></div><div><label>${uiText('servo_default_position')}</label><input type='number' min='0' max='100' value='${esc(pick(o.default_level,0))}' oninput='setField(\\\"outputs\\\",${i},\\\"default_level\\\",Number(this.value||0))'/></div></div><div class='row3'><div><label>${uiText('servo_feedback_min')}</label><input type='number' min='0' max='4095' value='${esc(pick(o.feedback_min_raw,300))}' oninput='setField(\\\"outputs\\\",${i},\\\"feedback_min_raw\\\",Number(this.value||0))'/></div><div><label>${uiText('servo_feedback_max')}</label><input type='number' min='0' max='4095' value='${esc(pick(o.feedback_max_raw,3700))}' oninput='setField(\\\"outputs\\\",${i},\\\"feedback_max_raw\\\",Number(this.value||0))'/></div><div><label>${uiText('servo_deadband')}</label><input type='number' min='1' max='20' value='${esc(pick(o.deadband_pct,2))}' oninput='setField(\\\"outputs\\\",${i},\\\"deadband_pct\\\",Number(this.value||2))'/></div></div><div class='row'><div><label>${uiText('servo_timeout')}</label><input type='number' min='1000' max='60000' value='${esc(pick(o.move_timeout_ms,15000))}' oninput='setField(\\\"outputs\\\",${i},\\\"move_timeout_ms\\\",Number(this.value||15000))'/></div><div><label><input type='checkbox' ${o.reverse_direction?'checked':''} onchange='setField(\\\"outputs\\\",${i},\\\"reverse_direction\\\",this.checked)' style='width:auto'/> ${uiText('servo_reverse')}</label></div></div>`:''}${renderOutputLiveCard(i,o)}</div>`;}).join('');}"
"function renderIo(){const boardProfile=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));const items=ioEntries();document.getElementById('io').innerHTML=items.length?items.map((entry,row)=>{const o=entry.data;const sec=entry.section;const idx=entry.idx;const isButton=entry.kind==='button';return `<div class='item'><div class='itemhead'><strong>${esc(o.name||o.id||(`${isButton?t('button_name'):t('io_name')} ${row+1}`))}</strong><button class='danger' onclick='removeItem(\\\"${sec}\\\",${idx})'>${t('remove')}</button></div><div class='row3'><div><label>${t('kind')}</label><select onchange='changeIoKind(\\\"${sec}\\\",${idx},this.value)'><option value='input' ${!isButton?'selected':''}>${t('kind_input')}</option><option value='button' ${isButton?'selected':''}>${t('kind_button')}</option></select></div><div><label>${t('id')}</label><input value='${esc(o.id||'')}' oninput='setField(\\\"${sec}\\\",${idx},\\\"id\\\",this.value)'/></div><div><label>${t('name')}</label><input value='${esc(o.name||'')}' oninput='setField(\\\"${sec}\\\",${idx},\\\"name\\\",this.value)'/></div></div><div class='row3'><div><label>${t('gpio')}</label><select onchange='setField(\\\"${sec}\\\",${idx},\\\"gpio\\\",Number(this.value))'>${gpioOptions(pick(o.gpio,0),boardProfile)}</select></div><div><label>${t('pull')}</label><select onchange='setField(\\\"${sec}\\\",${idx},\\\"pull\\\",this.value)'>${enumOptions(PULLS,pick(o.pull,'up'),PULL_LABELS)}</select></div>${isButton?`<div><label>${t('long_press_ms')}</label><input type='number' value='${esc(pick(o.long_press_ms,1000))}' oninput='setField(\\\"${sec}\\\",${idx},\\\"long_press_ms\\\",Number(this.value||1000))'/></div>`:`<div><label>${t('role')}</label><select onchange='setField(\\\"${sec}\\\",${idx},\\\"role\\\",this.value)'>${enumOptions(INPUT_ROLES,pick(o.role,'generic_binary'),INPUT_ROLE_LABELS)}</select></div>`}</div><div class='row'><div><label><input type='checkbox' ${o.inverted?'checked':''} onchange='setField(\\\"${sec}\\\",${idx},\\\"inverted\\\",this.checked)' style='width:auto'/> ${t('inverted')}</label></div><div><label><input type='checkbox' ${o.enabled!==false?'checked':''} onchange='setField(\\\"${sec}\\\",${idx},\\\"enabled\\\",this.checked)' style='width:auto'/> ${t('enabled')}</label></div></div>${isButton?actionEditor(sec,idx,'short',(o.actions||{}).short)+actionEditor(sec,idx,'long',(o.actions||{}).long):''}${renderIoLiveCard(entry)}</div>`;}).join(''):`<div class='muted'>${t('empty_io')}</div>`;}"
"function renderSensors(){const boardProfile=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));document.getElementById('sensors').innerHTML=cfg.sensors.map((o,i)=>{const type=pick(o.type,'ds18b20_bus');return `<div class='item'><div class='itemhead'><strong>${esc(o.name||o.id||(`${t('sensor_name')} ${i+1}`))}</strong><button class='danger' onclick='removeItem(\\\"sensors\\\",${i})'>${t('remove')}</button></div><div class='row'><div><label>${t('id')}</label><input value='${esc(o.id||'')}' oninput='setField(\\\"sensors\\\",${i},\\\"id\\\",this.value)'/></div><div><label>${t('name')}</label><input value='${esc(o.name||'')}' oninput='setField(\\\"sensors\\\",${i},\\\"name\\\",this.value)'/></div></div><div class='row3'><div><label>${t('type')}</label><select onchange='setField(\\\"sensors\\\",${i},\\\"type\\\",this.value)'>${enumOptions(SENSOR_TYPES,type,SENSOR_TYPE_LABELS)}</select></div><div><label>${t('poll_sec')}</label><input type='number' value='${esc(pick(o.poll_interval_sec,30))}' oninput='setField(\\\"sensors\\\",${i},\\\"poll_interval_sec\\\",Number(this.value||30))'/></div><div><label><input type='checkbox' ${o.enabled!==false?'checked':''} onchange='setField(\\\"sensors\\\",${i},\\\"enabled\\\",this.checked)' style='width:auto'/> ${t('enabled')}</label></div></div>${type==='ds18b20_bus'?`<div><label>${t('gpio')}</label><select onchange='setField(\\\"sensors\\\",${i},\\\"gpio\\\",Number(this.value))'>${gpioOptions(pick(o.gpio,0),boardProfile)}</select></div>`:`<div class='row3'><div><label>${t('sda')}</label><select onchange='setField(\\\"sensors\\\",${i},\\\"sda_gpio\\\",Number(this.value))'>${gpioOptions(pick(o.sda_gpio,0),boardProfile)}</select></div><div><label>${t('scl')}</label><select onchange='setField(\\\"sensors\\\",${i},\\\"scl_gpio\\\",Number(this.value))'>${gpioOptions(pick(o.scl_gpio,1),boardProfile)}</select></div><div><label>${t('address')}</label><input value='${esc(pick(o.address,type==='aht20'?56:type==='sht3x'?68:118))}' oninput='setField(\\\"sensors\\\",${i},\\\"address\\\",Number(this.value||0))'/></div></div>`}</div>`;}).join('');}"
"function boardHint(){const key=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));const hint=BOARD_HINTS[key]||BOARD_HINTS['esp32-c3-supermini'];return hint[lang]||hint.en||'';}"
"function renderMeta(){const boardProfile=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));const boardHintText=boardHint();const boardHintEl=document.getElementById('board_hint');document.getElementById('device_name').value=pick(cfg.device.name,'');document.getElementById('sta_ssid').value=pick(cfg.connectivity.sta.ssid,'');document.getElementById('sta_ssid').placeholder=t('select_network');document.getElementById('sta_pass').value=pick(cfg.connectivity.sta.pass,'');document.getElementById('mqtt_host').value=pick(cfg.connectivity.mqtt.host,'');document.getElementById('mqtt_port').value=pick(cfg.connectivity.mqtt.port,1883);document.getElementById('mqtt_user').value=pick(cfg.connectivity.mqtt.user,'');document.getElementById('mqtt_pass').value=pick(cfg.connectivity.mqtt.pass,'');document.getElementById('mqtt_topic_prefix').value=pick(cfg.connectivity.mqtt.topic_prefix,'');document.getElementById('mqtt_client_id').value=pick(cfg.connectivity.mqtt.client_id,'');document.getElementById('mqtt_discovery_prefix').value=pick(cfg.connectivity.mqtt.discovery_prefix,'homeassistant');document.getElementById('mqtt_enable').checked=cfg.connectivity.mqtt.enable===true;document.getElementById('mqtt_discovery').checked=cfg.connectivity.mqtt.discovery!==false;document.getElementById('mqtt_retain').checked=cfg.connectivity.mqtt.retain!==false;document.getElementById('board_profile').innerHTML=boardOptions(boardProfile);document.getElementById('board_profile').value=boardProfile;boardHintEl.textContent=boardHintText;boardHintEl.style.display=boardHintText?'block':'none';}"
"function updateMetaFromInputs(){cfg.device.name=document.getElementById('device_name').value.trim();cfg.connectivity.ap={};cfg.connectivity.sta.ssid=document.getElementById('sta_ssid').value.trim();cfg.connectivity.sta.pass=document.getElementById('sta_pass').value;cfg.connectivity.mqtt.enable=document.getElementById('mqtt_enable').checked;cfg.connectivity.mqtt.host=document.getElementById('mqtt_host').value.trim();cfg.connectivity.mqtt.port=Number(document.getElementById('mqtt_port').value||1883);cfg.connectivity.mqtt.user=document.getElementById('mqtt_user').value.trim();cfg.connectivity.mqtt.pass=document.getElementById('mqtt_pass').value;cfg.connectivity.mqtt.topic_prefix=document.getElementById('mqtt_topic_prefix').value.trim();cfg.connectivity.mqtt.client_id=document.getElementById('mqtt_client_id').value.trim();cfg.connectivity.mqtt.discovery_prefix=document.getElementById('mqtt_discovery_prefix').value.trim();cfg.connectivity.mqtt.discovery=document.getElementById('mqtt_discovery').checked;cfg.connectivity.mqtt.retain=document.getElementById('mqtt_retain').checked;cfg.device.board_profile=normalizeBoardProfile(document.getElementById('board_profile').value);}"
"function setBoardProfile(value){updateMetaFromInputs();cfg.device.board_profile=normalizeBoardProfile(value);render();}"
"function validateGpios(){const boardProfile=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));const used={};const errors=[];const touch=(label,g,opts)=>{if(g===undefined||g===null||g==='')return;const gpio=Number(g);const opt=opts||{};if(!Number.isInteger(gpio)){errors.push(`${label}: invalid GPIO`);return;}if(!gpioAllowed(boardProfile,gpio))errors.push(`${label}: ${gpioForbiddenText(boardProfile,gpio)}`);if(opt.adc&&!adcFeedbackGpios(boardProfile).includes(gpio))errors.push(`${label}: ${lang==='ru'?'\\u043D\\u0443\\u0436\\u0435\\u043D ADC-\\u0441\\u043E\\u0432\\u043C\\u0435\\u0441\\u0442\\u0438\\u043C\\u044B\\u0439 GPIO0..GPIO4':'requires ADC-capable GPIO0..GPIO4'}`);const key=String(gpio);used[key]=used[key]||[];used[key].push(label);};cfg.outputs.forEach(o=>{const name=`${t('output_name')} ${o.id||o.name||'?'}`;touch(name,o.gpio);if(o.type==='pwm')touch(`${name} (${uiText('power_relay')})`,o.power_relay_gpio);if(o.type==='servo_5wire'){touch(`${name} (B)`,o.gpio_b);touch(`${name} (${uiText('servo_feedback')})`,o.feedback_gpio,{adc:true});}});cfg.inputs.forEach(o=>touch(`${t('io_name')} ${o.id||o.name||'?'}`,o.gpio));cfg.buttons.forEach(o=>touch(`${t('button_name')} ${o.id||o.name||'?'}`,o.gpio));cfg.sensors.forEach(o=>{if(o.type==='ds18b20_bus'){touch(`${t('sensor_name')} ${o.id||o.name||'?'}`,o.gpio);}else{touch('i2c_sda',o.sda_gpio);touch('i2c_scl',o.scl_gpio);}});Object.entries(used).forEach(([gpio,list])=>{if(list.length>1&&!(list.every(v=>v==='i2c_sda')||list.every(v=>v==='i2c_scl')))errors.push(`GPIO${gpio}: ${list.join(', ')}`);});document.getElementById('pinout_summary').innerHTML=errors.length?`<span class='err'>${t('conflicts')}:</span><br>${errors.map(esc).join('<br>')}`:`<span class='ok'>${t('no_gpio_conflicts')}</span>`;return errors.length===0;}"
"function collectPinUsage(){const usage={};const add=(gpio,kind,label,share)=>{const num=Number(gpio);if(!Number.isInteger(num))return;const key=String(num);usage[key]=usage[key]||[];usage[key].push({kind,label,share:share||''});};cfg.outputs.forEach(o=>{const name=`${t('output_name')} ${o.id||o.name||'?'}`;add(o.gpio,'output',name,'');if(o.type==='pwm')add(o.power_relay_gpio,'output',`${name} (${uiText('power_relay')})`,'');if(o.type==='servo_5wire'){add(o.gpio_b,'output',`${name} (B)`,'');add(o.feedback_gpio,'sensor',`${name} (${uiText('servo_feedback')})`,'');}});cfg.inputs.forEach(o=>add(o.gpio,'io',`${t('io_name')} ${o.id||o.name||'?'}`,''));cfg.buttons.forEach(o=>add(o.gpio,'io',`${t('button_name')} ${o.id||o.name||'?'}`,''));cfg.sensors.forEach(o=>{const name=`${t('sensor_name')} ${o.id||o.name||'?'}`;if(o.type==='ds18b20_bus'){add(o.gpio,'sensor',`${name} (${o.type||'sensor'})`,'');}else{add(o.sda_gpio,'sensor',`${name} SDA`,'i2c_sda');add(o.scl_gpio,'sensor',`${name} SCL`,'i2c_scl');}});return usage;}"
"function pinoutDetailsHtml(profile,gpio,usage){if(gpio===undefined||gpio===null||gpio==='')return '';const info=summarizePinUsage(profile,gpio,usage);const body=info.lines.length?info.lines.map(esc).join('<br>'):esc(pinoutText('free'));return `<strong>GPIO${gpio}</strong> \\u00B7 ${esc(info.title)}<br>${body}`;}"
"function pinSpecState(profile,pin,usage){if(pin.type==='power'||pin.type==='ground'||pin.type==='special')return{state:pin.type,title:pinoutText(pin.type),lines:[pin.label]};return summarizePinUsage(profile,pin.gpio,usage);}"
"function pinTagClass(tag){if(/^A\\d+$/.test(tag))return'pin-tag-adc';if(tag==='SCK'||tag==='MISO'||tag==='MOSI'||tag==='SS'||tag==='SPIHD'||tag==='SPIWP'||tag==='VDDSPI')return'pin-tag-spi';if(tag==='SDA'||tag==='SCL')return'pin-tag-i2c';if(tag==='RX'||tag==='TX'||/^U\\d/.test(tag))return'pin-tag-uart';if(tag==='BOOT'||tag==='PWM1'||tag==='PWM4'||tag==='USB-'||tag==='USB+')return'pin-tag-special';return'pin-tag-spi';}"
"function renderPinTags(pin,side,y){const tags=Array.isArray(pin.tags)?pin.tags:[];if(!tags.length)return'';const width=40;return tags.map((tag,idx)=>{const cls=pinTagClass(tag);const finalX=side==='left'?(10+idx*(width+6)):(442+idx*(width+6));return `<g class='pin-tag ${cls}'><rect class='pin-tag-box' x='${finalX}' y='${y}' width='${width}' height='20' rx='10' ry='10'/><text x='${finalX+(width/2)}' y='${y+13}' text-anchor='middle'>${esc(tag)}</text></g>`;}).join('');}"
"function buildPinoutSvg(profile,selected,usage){const spec=BOARD_PINOUTS[profile]||BOARD_PINOUTS['esp32-c3-supermini'];const rows=Math.max(spec.left.length,spec.right.length);const width=540;const height=Math.max(430,130+rows*42);const boardX=210;const boardY=34;const boardW=120;const boardH=height-68;const pinW=74;const pinH=24;const leftX=126;const rightX=340;const startY=74;const step=42;const renderSide=(pins,side)=>pins.map((pin,index)=>{const y=startY+index*step;const info=pinSpecState(profile,pin,usage);const gpio=pin.gpio;const selectedClass=(gpio!==undefined&&Number(selected)===gpio)?' pin-selected':'';const lineStart=side==='left'?boardX:boardX+boardW;const lineEnd=side==='left'?leftX+pinW:rightX;const boxX=side==='left'?leftX:rightX;const textX=boxX+(pinW/2);const hit=gpio!==undefined?`<rect class='pin-hit' x='${boxX-4}' y='${y-4}' width='${pinW+8}' height='${pinH+8}' onclick='showPinDetails(${gpio})'/>`:'';const tags=renderPinTags(pin,side,y+2);return `<g class='pin-${info.state}${selectedClass}'><line class='pin-wire' x1='${lineStart}' y1='${y+12}' x2='${lineEnd}' y2='${y+12}'/><rect class='pin-body' x='${boxX}' y='${y}' width='${pinW}' height='${pinH}' rx='12' ry='12'/><text class='pin-text' x='${textX}' y='${y+16}' text-anchor='middle'>${esc(pin.label)}</text>${tags}${hit}</g>`;}).join('');const notchX=boardX+boardW/2-18;return `<svg class='pinout-svg' viewBox='0 0 ${width} ${height}' role='img' aria-label='${esc(boardProfileName(profile))}'><rect class='board-shell' x='${boardX}' y='${boardY}' width='${boardW}' height='${boardH}' rx='20' ry='20'/><rect class='board-top' x='${boardX+24}' y='${boardY-8}' width='${boardW-48}' height='14' rx='6' ry='6'/><path class='board-notch' d='M ${notchX} ${boardY+56} h 36 l -8 18 h -20 z'/><text class='board-label' x='270' y='${boardY+boardH/2-6}' text-anchor='middle'>ESP32-C3</text><text class='board-label' x='270' y='${boardY+boardH/2+20}' text-anchor='middle'>${esc(spec.title)}</text><text class='board-sub' x='270' y='${boardY+boardH-18}' text-anchor='middle'>${esc(spec.subtitle)}</text>${renderSide(spec.left,'left')}${renderSide(spec.right,'right')}</svg>`;}"
"function renderPinout(selected){const profile=normalizeBoardProfile(pick(cfg.device.board_profile,'esp32-c3-supermini'));const usage=collectPinUsage();const detailsEl=document.getElementById('pinout_details');const detailsHtml=pinoutDetailsHtml(profile,selected,usage);document.getElementById('pinout_title').textContent=pinoutText('title');document.getElementById('pinout_profile').textContent=boardProfileName(profile);document.getElementById('pinout_legend').innerHTML=pinoutLegendHtml();document.getElementById('pinout_board').innerHTML=buildPinoutSvg(profile,selected,usage);detailsEl.innerHTML=detailsHtml;detailsEl.style.display=detailsHtml?'block':'none';}"
"function showPinDetails(gpio){renderPinout(Number(gpio));}"
"function applyI18n(){const subtitle=t('subtitle');document.documentElement.lang=(lang==='ru'?'ru':'en');document.title=t('title');document.getElementById('lang_select').value=lang;document.getElementById('page_title').textContent=t('title');document.getElementById('page_subtitle').textContent=subtitle;document.getElementById('page_subtitle').style.display=subtitle?'block':'none';document.getElementById('btn_save_apply').textContent=t('save_apply');document.getElementById('btn_factory_reset').textContent=t('factory_reset');document.getElementById('connectivity_title').textContent=t('connectivity');document.getElementById('lbl_device_name').textContent=t('device_name');document.getElementById('lbl_sta_ssid').textContent=t('sta_ssid');document.getElementById('lbl_sta_pass').textContent=t('sta_pass');document.getElementById('lbl_mqtt_host').textContent=t('mqtt_host');document.getElementById('lbl_mqtt_port').textContent=t('mqtt_port');document.getElementById('lbl_mqtt_user').textContent=t('mqtt_user');document.getElementById('lbl_mqtt_pass').textContent=t('mqtt_pass');document.getElementById('lbl_topic_prefix').textContent=t('topic_prefix');document.getElementById('lbl_client_id').textContent=t('client_id');document.getElementById('lbl_discovery_prefix').textContent=t('discovery_prefix');document.getElementById('lbl_board_profile').textContent=t('board_profile');document.getElementById('lbl_mqtt_enable').textContent=t('mqtt_enabled');document.getElementById('lbl_mqtt_discovery').textContent=t('ha_discovery');document.getElementById('lbl_mqtt_retain').textContent=t('retain');document.getElementById('outputs_title').textContent=t('outputs');document.getElementById('btn_add_output').textContent=t('add_output');document.getElementById('io_title').textContent=t('io_title');document.getElementById('btn_add_io').textContent=t('add_io');document.getElementById('sensors_title').textContent=t('sensors');document.getElementById('btn_add_sensor').textContent=t('add_sensor');}"
"async function ensureWifiScan(){if(wifiScanLoaded)return;if(wifiScanInFlight){await wifiScanInFlight;return;}wifiScanInFlight=scanWifi(true).finally(()=>{wifiScanInFlight=null;});await wifiScanInFlight;}"
"function render(){ensure();applyI18n();renderMeta();renderOutputs();renderIo();renderSensors();renderPinout();validateGpios();refreshLiveWidgets();startLivePolling();}"
"function setLang(value){lang=(value==='en'?'en':'ru');localStorage.setItem('ui_lang',lang);render();}"
"function addOutput(){cfg.outputs.push({id:`out${cfg.outputs.length+1}`,name:`${t('output_name')} ${cfg.outputs.length+1}`,type:'relay',enabled:true,gpio:0,active_level:1,default_on:false});render();}"
"function addIo(){cfg.inputs.push({id:`in${cfg.inputs.length+1}`,name:`${t('io_name')} ${cfg.inputs.length+1}`,type:'digital',enabled:true,gpio:0,pull:'up',inverted:false,role:'generic_binary'});render();}"
"function addSensor(){cfg.sensors.push({id:`sensor${cfg.sensors.length+1}`,name:`${t('sensor_name')} ${cfg.sensors.length+1}`,type:'ds18b20_bus',enabled:true,gpio:0,poll_interval_sec:30});render();}"
"async function loadCfg(){cfg=await fetch('/api/config').then(r=>r.json());ensure();render();await ensureWifiScan();await pollLiveModules(true);}"
"async function scanWifi(initial){try{const r=await fetch('/api/wifi/scan');if(!r.ok)throw new Error(await r.text()||('HTTP '+r.status));const j=await r.json();const nets=j.networks||[];const list=document.getElementById('wifi_scan_list');list.innerHTML=nets.map(n=>`<option value='${esc(n.ssid)}'>${esc(n.ssid)} (${n.rssi} dBm)</option>`).join('');wifiScanLoaded=nets.length>0;setMsg(fmt(t('found_networks'),{count:nets.length}),true);}catch(e){wifiScanLoaded=false;if(!initial)setMsg(String(e),false);}}"
"async function saveOnly(){updateMetaFromInputs();render();if(!validateGpios())throw new Error(gpioSaveBlockedText());const r=await fetch('/api/config',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(cfg)});const text=await r.text();if(!r.ok)throw new Error(text||('HTTP '+r.status));setMsg(t('msg_saved'),true);}"
"async function saveAndApply(){try{await saveOnly();const r=await fetch('/api/apply',{method:'POST'});if(!r.ok)throw new Error(await r.text());setMsg(t('msg_saved_apply'),true);}catch(e){setMsg(String(e),false);}}"
"async function applyOnly(){try{const r=await fetch('/api/apply',{method:'POST'});if(!r.ok)throw new Error(await r.text());setMsg(t('msg_apply'),true);}catch(e){setMsg(String(e),false);}}"
"async function factoryReset(){try{if(!confirm(t('confirm_reset')))return;const r=await fetch('/api/factory-reset',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({confirm:'ERASE'})});if(!r.ok)throw new Error(await r.text());setMsg(t('msg_reset'),true);}catch(e){setMsg(String(e),false);}}"
"window.setField=setField;window.setNested=setNested;window.removeItem=removeItem;window.addOutput=addOutput;window.addIo=addIo;window.addSensor=addSensor;window.saveAndApply=saveAndApply;window.factoryReset=factoryReset;window.setLang=setLang;window.changeIoKind=changeIoKind;window.ensureWifiScan=ensureWifiScan;window.setBoardProfile=setBoardProfile;window.showPinDetails=showPinDetails;window.togglePwmPowerRelay=togglePwmPowerRelay;window.setOptionalPwmPowerRelayGpio=setOptionalPwmPowerRelayGpio;window.setWs2812Mode=setWs2812Mode;window.setOutputType=setOutputType;window.testOutput=testOutput;"
"loadCfg();"
"</script></div></body></html>";
